import{_ as e,o as t,c as a,a0 as i}from"./chunks/framework.CrGeEOPE.js";const b=JSON.parse('{"title":"Zero-Allocation Principle","description":"","frontmatter":{"head":[["link",{"rel":"canonical","href":"https://qbuem.com/qbuem-json/theory/zero-allocation.html"}]]},"headers":[],"relativePath":"theory/zero-allocation.md","filePath":"theory/zero-allocation.md"}'),l={name:"theory/zero-allocation.md"};function d(o,s,r,n,c,p){return t(),a("div",null,[...s[0]||(s[0]=[i(`<h1 id="zero-allocation-principle" tabindex="-1">Zero-Allocation Principle <a class="header-anchor" href="#zero-allocation-principle" aria-label="Permalink to &quot;Zero-Allocation Principle&quot;">​</a></h1><p>The single greatest source of latency jitter in C++ is the heap. Every <code>malloc</code> call can stall a thread for microseconds. qbuem-json eliminates all heap allocations from its hot path through three complementary techniques.</p><hr><h2 id="why-heap-allocation-hurts" tabindex="-1">Why Heap Allocation Hurts <a class="header-anchor" href="#why-heap-allocation-hurts" aria-label="Permalink to &quot;Why Heap Allocation Hurts&quot;">​</a></h2><p>A single <code>malloc</code> is not a simple operation. Under the hood, it involves:</p><div class="bd-diagram"><div class="bd-col"><div class="bd-box bd-box--red">malloc(n) called</div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-group" style="width:100%;max-width:480px;"><div class="bd-group__title">Hidden costs inside the allocator</div><div class="bd-group__body"><div class="bd-steps"><div class="bd-step"><div class="bd-step__num">1</div><div class="bd-step__body"><div class="bd-step__title">Acquire global allocator mutex</div><div class="bd-step__desc">May block if another thread holds the lock</div></div></div><div class="bd-step"><div class="bd-step__num">2</div><div class="bd-step__body"><div class="bd-step__title">Size-class lookup</div><div class="bd-step__desc">Find a free block in the free list</div></div></div><div class="bd-step"><div class="bd-step__num">3</div><div class="bd-step__body"><div class="bd-step__title">Possible mmap / brk syscall</div><div class="bd-step__desc">Kernel mode switch: ~1,000 ns</div></div></div><div class="bd-step"><div class="bd-step__num">4</div><div class="bd-step__body"><div class="bd-step__title">Cold cache miss on returned memory</div><div class="bd-step__desc">TLB miss + page fault: ~100 ns</div></div></div><div class="bd-step"><div class="bd-step__num">5</div><div class="bd-step__body"><div class="bd-step__title">Fragmentation accumulates</div><div class="bd-step__desc">RSS grows even if logical usage stays flat</div></div></div></div></div></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-box bd-box--orange">Pointer returned to caller<br><small>(after 50–5,000 ns depending on system state)</small></div></div></div><p>For a library parsing thousands of messages per second, these costs compound into <strong>milliseconds of unbudgeted latency per second</strong>. A single 5 μs stall can cascade into a missed deadline in HFT or game-server contexts.</p><hr><h2 id="the-three-layer-solution" tabindex="-1">The Three-Layer Solution <a class="header-anchor" href="#the-three-layer-solution" aria-label="Permalink to &quot;The Three-Layer Solution&quot;">​</a></h2><p>qbuem-json eliminates heap allocations with three coordinated techniques:</p><div class="bd-diagram"><div class="bd-col"><div class="bd-steps" style="max-width:540px;width:100%;"><div class="bd-step"><div class="bd-step__num" style="background:#0097a7;">1</div><div class="bd-step__body"><div class="bd-step__title" style="color:#0097a7;">Layer 1 — Pre-allocated Tape</div><div class="bd-step__desc">qbuem::Document owns one contiguous tape[]. All TapeNodes written here. Capacity grows once, reused forever.</div></div></div><div class="bd-step"><div class="bd-step__num" style="background:#9c27b0;">2</div><div class="bd-step__body"><div class="bd-step__title" style="color:#9c27b0;">Layer 2 — Zero-Copy String Views</div><div class="bd-step__desc">qbuem::Value stores std::string_view pointing into the caller&#39;s input buffer. No memcpy, no heap string.</div></div></div><div class="bd-step"><div class="bd-step__num" style="background:#4caf50;">3</div><div class="bd-step__body"><div class="bd-step__title" style="color:#4caf50;">Layer 3 — Stream-Push Serialization</div><div class="bd-step__desc">qbuem::write_to(buffer, value) writes tokens directly into the caller&#39;s buffer. No intermediate tree, no temporary string.</div></div></div></div></div></div><hr><h2 id="layer-1-tape-pre-allocation-and-reuse" tabindex="-1">Layer 1: Tape Pre-Allocation and Reuse <a class="header-anchor" href="#layer-1-tape-pre-allocation-and-reuse" aria-label="Permalink to &quot;Layer 1: Tape Pre-Allocation and Reuse&quot;">​</a></h2><p><code>qbuem::Document</code> allocates its internal tape <strong>once</strong> on first use. Every subsequent <code>parse()</code> call on the same <code>Document</code> resets the write pointer to zero — reusing existing memory without any allocator involvement:</p><div class="bd-diagram"><div class="bd-split" style="max-width:600px;margin:0 auto;"><div class="bd-group"><div class="bd-group__title">First parse()</div><div class="bd-group__body"><div class="bd-box" style="font-size:0.78rem;">Document constructed<br><small>tape = nullptr, capacity = 0</small></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-box bd-box--orange" style="font-size:0.78rem;">parse() called<br><small>1× realloc to N slots</small></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-box bd-box--teal" style="font-size:0.78rem;">tape: capacity=N, used=k</div></div></div><div class="bd-group"><div class="bd-group__title">Second parse() — same Document</div><div class="bd-group__body"><div class="bd-box" style="font-size:0.78rem;">tape: capacity=N<br><small>(unchanged)</small></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-box bd-box--green" style="font-size:0.78rem;">write_head_ = 0 (reset only)<br><small>zero malloc — buffer already large enough</small></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-box bd-box--teal" style="font-size:0.78rem;">tape: capacity=N, used=k2</div></div></div></div></div><h3 id="what-this-looks-like-in-a-hot-loop" tabindex="-1">What this looks like in a hot loop <a class="header-anchor" href="#what-this-looks-like-in-a-hot-loop" aria-label="Permalink to &quot;What this looks like in a hot loop&quot;">​</a></h3><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">qbuem</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::Document doc;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         // tape is empty — no allocation yet</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">while</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) {</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    auto</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> msg  </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> recv_message</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    auto</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> root </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> qbuem</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">parse</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(doc, msg);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  // zero malloc after first call</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    handle</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(root);</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    // tape is implicitly reused on the next loop iteration</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>After the first message warms up the tape, <strong>every subsequent parse is allocation-free</strong>.</p><h3 id="tape-capacity-growth-policy" tabindex="-1">Tape capacity growth policy <a class="header-anchor" href="#tape-capacity-growth-policy" aria-label="Permalink to &quot;Tape capacity growth policy&quot;">​</a></h3><p>The tape uses a doubling strategy. If an incoming document requires more nodes than the current capacity, <code>realloc</code> is called once to double the buffer:</p><div class="bd-diagram"><div class="bd-col"><div class="bd-pipeline" style="flex-direction:column;align-items:stretch;max-width:400px;margin:0 auto;"><div class="bd-pipe-stage"><div class="bd-pipe-stage__label">Initial</div><div class="bd-pipe-stage__main">capacity = 0</div></div><div class="bd-pipe-arrow" style="align-self:center;transform:rotate(90deg);">→</div><div class="bd-pipe-stage bd-box--orange" style="border-color:#ff9800;background:rgba(255,152,0,0.06);"><div class="bd-pipe-stage__label">1× realloc</div><div class="bd-pipe-stage__main">capacity = 256</div><div class="bd-pipe-stage__note">first doc (200 nodes)</div></div><div class="bd-pipe-arrow" style="align-self:center;transform:rotate(90deg);">→</div><div class="bd-pipe-stage bd-box--orange" style="border-color:#ff9800;background:rgba(255,152,0,0.06);"><div class="bd-pipe-stage__label">1× realloc</div><div class="bd-pipe-stage__main">capacity = 512</div><div class="bd-pipe-stage__note">doc with 300 nodes</div></div><div class="bd-pipe-arrow" style="align-self:center;transform:rotate(90deg);">→</div><div class="bd-pipe-stage bd-box--orange" style="border-color:#ff9800;background:rgba(255,152,0,0.06);"><div class="bd-pipe-stage__label">1× realloc</div><div class="bd-pipe-stage__main">capacity = 1024</div><div class="bd-pipe-stage__note">doc with 600 nodes</div></div><div class="bd-pipe-arrow" style="align-self:center;transform:rotate(90deg);">→</div><div class="bd-pipe-stage bd-box--green" style="border-color:#4caf50;background:rgba(76,175,80,0.08);"><div class="bd-pipe-stage__label">Stable</div><div class="bd-pipe-stage__main">capacity = 1024</div><div class="bd-pipe-stage__note">all future docs → zero allocations</div></div></div></div></div><p>In practice, documents in a single application tend to have stable schemas — after a few warmup parses, capacity stabilizes and no further allocations occur.</p><hr><h2 id="layer-2-zero-copy-string-views" tabindex="-1">Layer 2: Zero-Copy String Views <a class="header-anchor" href="#layer-2-zero-copy-string-views" aria-label="Permalink to &quot;Layer 2: Zero-Copy String Views&quot;">​</a></h2><p>When qbuem-json encounters a string literal, it does <strong>not</strong> allocate a <code>std::string</code> or call <code>memcpy</code>. Instead, the <code>KEY</code> or <code>STRING</code> TapeNode stores a <code>std::string_view</code> pointing directly into the caller&#39;s input buffer:</p><div class="bd-diagram"><div class="bd-col"><div class="bd-group" style="width:100%;max-width:480px;"><div class="bd-group__title">Input Buffer — caller-owned (stack / recv buf / mmap)</div><div class="bd-group__body"><div class="bd-box bd-box--blue">{ &quot;name&quot;: &quot;Bob&quot; }</div></div></div><div class="bd-row" style="gap:3rem;"><div class="bd-arrow"><div class="bd-arrow__icon">↓</div><div class="bd-arrow__label">zero-copy pointer</div></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div><div class="bd-arrow__label">zero-copy pointer</div></div></div><div class="bd-group" style="width:100%;max-width:480px;"><div class="bd-group__title">Document Tape</div><div class="bd-group__body"><div class="bd-tape-strip" style="justify-content:center;"><div class="bd-tape-cell bd-tape-cell--key"><span class="bd-tape-cell__idx">tape[1] KEY</span><span class="bd-tape-cell__tag">string_view</span><span class="bd-tape-cell__val">&amp;buf[2], len=4 → &quot;name&quot;</span></div><div class="bd-tape-cell bd-tape-cell--str"><span class="bd-tape-cell__idx">tape[2] STRING</span><span class="bd-tape-cell__tag">string_view</span><span class="bd-tape-cell__val">&amp;buf[9], len=3 → &quot;Bob&quot;</span></div></div></div></div></div></div><p>Accessing <code>root[&quot;name&quot;]</code> returns a <code>string_view</code> pointing at <code>buf[2]</code> with <code>len=4</code>. <strong>Zero bytes are allocated, zero bytes are copied.</strong></p><blockquote><p><strong>Lifetime rule</strong>: <code>string_view</code> values are valid as long as both the <code>Document</code> and the input buffer are alive. Do not hold a <code>string_view</code> after either goes out of scope.</p></blockquote><h3 id="contrast-with-nlohmann-json" tabindex="-1">Contrast with <code>nlohmann/json</code> <a class="header-anchor" href="#contrast-with-nlohmann-json" aria-label="Permalink to &quot;Contrast with \`nlohmann/json\`&quot;">​</a></h3><div class="bd-diagram"><div class="bd-split" style="max-width:600px;margin:0 auto;gap:1rem;"><div class="bd-group"><div class="bd-group__title" style="color:#f44336;border-bottom-color:#f44336;">nlohmann::json</div><div class="bd-group__body"><div class="bd-box" style="font-size:0.78rem;">Input: { name: Bob }</div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-box bd-box--red" style="font-size:0.75rem;">malloc(4) → &quot;name&quot;<br><small>(new std::string)</small></div><div class="bd-box bd-box--red" style="font-size:0.75rem;">malloc(3) → &quot;Bob&quot;<br><small>(new std::string)</small></div><div class="bd-box bd-box--red" style="font-size:0.75rem;">… × N for every string</div></div></div><div class="bd-group"><div class="bd-group__title" style="color:#0097a7;border-bottom-color:#0097a7;">qbuem::json</div><div class="bd-group__body"><div class="bd-box" style="font-size:0.78rem;">Input: { name: Bob }</div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div></div><div class="bd-box bd-box--green" style="font-size:0.75rem;">string_view { &amp;buf[2], 4 }<br><small>8 bytes — no heap</small></div><div class="bd-box bd-box--green" style="font-size:0.75rem;">string_view { &amp;buf[9], 3 }<br><small>8 bytes — no heap</small></div></div></div></div></div><hr><h2 id="layer-3-stream-push-serialization" tabindex="-1">Layer 3: Stream-Push Serialization <a class="header-anchor" href="#layer-3-stream-push-serialization" aria-label="Permalink to &quot;Layer 3: Stream-Push Serialization&quot;">​</a></h2><p>Traditional serializers construct an intermediate in-memory JSON tree, then walk it to produce the output string. qbuem-json uses a <strong>stream-push model</strong>: it walks your data structure once and writes tokens directly into the output buffer:</p><div class="bd-diagram"><div class="bd-split" style="max-width:640px;margin:0 auto;gap:1rem;"><div class="bd-group"><div class="bd-group__title">Traditional — two-phase</div><div class="bd-group__body"><div class="bd-box" style="font-size:0.78rem;">User data (your structs)</div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div><div class="bd-arrow__label">phase 1: build tree (N mallocs)</div></div><div class="bd-box bd-box--red" style="font-size:0.78rem;">Intermediate JSON tree<br><small>heap allocated — O(N) nodes</small></div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div><div class="bd-arrow__label">phase 2: stringify (1 malloc)</div></div><div class="bd-box" style="font-size:0.78rem;">Output string</div></div></div><div class="bd-group"><div class="bd-group__title">qbuem-json — stream-push</div><div class="bd-group__body"><div class="bd-box" style="font-size:0.78rem;">User data (your structs)</div><div class="bd-arrow"><div class="bd-arrow__icon">↓</div><div class="bd-arrow__label">single pass · zero intermediate · zero copies</div></div><div class="bd-box bd-box--green" style="font-size:0.78rem;">Output buffer<br><small>(caller pre-allocated)</small></div></div></div></div></div><div class="language-cpp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">std</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::string buf;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">buf.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">reserve</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8192</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          // warm up once</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">for</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">auto&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> event : stream) {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    buf.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clear</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    qbuem</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">::</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">write_to</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(buf, event);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // zero malloc — writes directly into buf</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    send_to_kafka</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(buf);</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>After the first call warms the buffer, <strong>every subsequent serialization is allocation-free</strong>.</p><hr><h2 id="allocation-profile-measured-on-twitter-json-631-kb" tabindex="-1">Allocation Profile: Measured on twitter.json (631 KB) <a class="header-anchor" href="#allocation-profile-measured-on-twitter-json-631-kb" aria-label="Permalink to &quot;Allocation Profile: Measured on twitter.json (631 KB)&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">Operation</th><th style="text-align:right;">nlohmann/json</th><th style="text-align:right;">simdjson</th><th style="text-align:right;">qbuem-json</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Allocations per parse</strong></td><td style="text-align:right;">~11,000</td><td style="text-align:right;">2 (workspace)</td><td style="text-align:right;"><strong>0</strong> (after warmup)</td></tr><tr><td style="text-align:left;"><strong>Allocations per serialize</strong></td><td style="text-align:right;">~5,000</td><td style="text-align:right;">N/A (read-only)</td><td style="text-align:right;"><strong>0</strong> (with <code>write_to</code>)</td></tr><tr><td style="text-align:left;"><strong>Peak RSS</strong></td><td style="text-align:right;">27.4 MB</td><td style="text-align:right;">11.0 MB</td><td style="text-align:right;"><strong>3.4 MB</strong></td></tr><tr><td style="text-align:left;"><strong>Heap fragmentation (1M calls)</strong></td><td style="text-align:right;">severe</td><td style="text-align:right;">moderate</td><td style="text-align:right;"><strong>none</strong></td></tr><tr><td style="text-align:left;"><strong>Allocator lock contention</strong></td><td style="text-align:right;">high</td><td style="text-align:right;">low</td><td style="text-align:right;"><strong>zero</strong></td></tr></tbody></table><hr><h2 id="latency-percentile-impact" tabindex="-1">Latency Percentile Impact <a class="header-anchor" href="#latency-percentile-impact" aria-label="Permalink to &quot;Latency Percentile Impact&quot;">​</a></h2><p>For real-time systems, <strong>tail latency</strong> matters more than average. Heap allocations cause unpredictable spikes:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Percentile</th><th style="text-align:right;">nlohmann/json</th><th style="text-align:right;">qbuem-json</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>p50</strong></td><td style="text-align:right;">6 μs</td><td style="text-align:right;"><strong>0.3 μs</strong></td></tr><tr><td style="text-align:left;"><strong>p99</strong></td><td style="text-align:right;">47 μs ← malloc pressure</td><td style="text-align:right;"><strong>0.4 μs</strong></td></tr><tr><td style="text-align:left;"><strong>p99.9</strong></td><td style="text-align:right;">312 μs ← OS page fault</td><td style="text-align:right;"><strong>0.5 μs</strong></td></tr></tbody></table><p>For systems with a 1 μs parse budget (co-located HFT, kernel-bypass networking, FPGA gateway), the difference between <code>nlohmann</code> and qbuem-json is not &quot;faster&quot; — it is the difference between <strong>viable</strong> and <strong>not viable</strong>.</p>`,44)])])}const v=e(l,[["render",d]]);export{b as __pageData,v as default};
